const express = require('express');
const cors = require('cors');
const jwt = require('jsonwebtoken');
const { MagicBell } = require('magicbell-js/project-client');

const app = express();
app.use(cors());

const PORT = 3001;
const runId = process.env.ZEALT_RUN_ID || 'local';
const rawEmail = process.env.MAGICBELL_EMAIL || 'test@example.com';
const [emailPrefix, emailDomain] = rawEmail.split('@');
const email = `${emailPrefix}+${runId}@${emailDomain}`;
const externalId = `user-${runId}`;

const magicbellClient = new MagicBell({
  apiKey: process.env.MAGICBELL_API_KEY,
  apiSecret: process.env.MAGICBELL_API_SECRET,
});

async function init() {
  try {
    // Upsert user
    console.log(`Upserting user ${externalId} with email ${email}`);
    await magicbellClient.users.create({
      external_id: externalId,
      email: email,
    });

    console.log('User created/upserted');

    // Send broadcast
    console.log(`Sending broadcast to user ${externalId}`);
    await magicbellClient.notifications.create({
      title: `Test Notification ${runId}`,
      content: 'This is a test',
      recipients: [{ external_id: externalId }]
    });
    console.log('Broadcast sent');

  } catch (err) {
    console.error('Error during init:', err);
  }
}

app.get('/token', (req, res) => {
  const token = jwt.sign(
    { external_id: externalId },
    process.env.MAGICBELL_SECRET_KEY,
    { expiresIn: '1h' }
  );
  res.json({ token, externalId, email });
});

app.listen(PORT, () => {
  console.log(`Backend listening on port ${PORT}`);
  init();
});

import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  server: {
    port: 3000,
    strictPort: true
  }
});

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App.jsx';

ReactDOM.createRoot(document.getElementById('root')).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

