/**
 * A floating version of the notification inbox, toggled by a button.
 *
 * Renders the inbox inside a floating panel positioned relative to a trigger.
 * Ideal for embedding in navigation bars or headers. Supports full customization
 * of placement, dimensions, trigger, and inbox content.
 *
 * @event { notification: Notification } mb-notification-click - Emitted when a notification item is clicked. Call event.preventDefault() to stop default navigation.
 */
type FloatingInboxProps = {
    /**
     * The width of the floating inbox panel in pixels.
     * @default 400
     */
    width?: FloatingUIProps["width"];
    /**
     * The height of the floating inbox panel in pixels.
     * @default 400
     */
    height?: FloatingUIProps["height"];
    /**
     * Offset of the inbox from the trigger button, in pixels.
     * Can be a single number or an object with main/cross axis.
     * @type {OffsetOptions}
     * @default 8
     */
    offset?: FloatingUIProps["offset"];
    /**
     * Where to place the inbox relative to the trigger button.
     * E.g. 'bottom-end', 'top-start', etc.
     * @type {Placement}
     * @default bottom-start
     */
    placement?: FloatingUIProps["placement"];
    /**
     * Whether the inbox should be open by default.
     * @default false
     */
    defaultOpen?: FloatingUIProps["defaultOpen"];
    /**
     * Controlled open state. When provided, component becomes controlled
     * and will not close on outside click or Escape by itself.
     */
    open?: FloatingUIProps["open"];
    /**
     * Called whenever the user intends to change the open state.
     * Receives the next state and the reason: 'toggle' | 'outside' | 'escape'.
     */
    onOpenChange?: FloatingUIProps["onOpenChange"];
    /**
     * Called when a notification item is clicked.
     * Call `event.preventDefault()` to prevent the default behavior.
     */
    onNotificationClick?: (event: Event, detail: {
        notification: Notification;
    }) => void;
    /**
     * The component used to trigger the inbox, typically a bell icon.
     * It will receive `onClick` and `ref` props.
     * @type {Component}
     * @default InboxButton
     */
    ButtonComponent?: FloatingUIProps["TriggerComponent"];
    /**
     * The inbox component to render inside the floating panel.
     * Defaults to `<Inbox />` if not provided.
     * @type {Component}
     * @default Inbox
     */
    InboxComponent?: FloatingUIProps["FloatingComponent"];
