import React, { useEffect, useState } from 'react';
import { MagicBellProvider, FloatingInbox, Inbox } from '@magicbell/react';

const CustomNotificationItem = ({ notification }) => {
  console.log('Notification item props:', { notification });

  const handleMarkAsRead = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (notification.markAsRead) {
      notification.markAsRead();
    }
  };

  return (
    <div className="custom-notification-item">
      <div className="custom-notification-title">{notification.title}</div>
      <div className="custom-notification-content">{notification.content}</div>
      {!notification.readAt && (
        <button className="custom-mark-read-btn" onClick={handleMarkAsRead}>
          Mark as Read
        </button>
      )}
    </div>
  );
};

export default function App() {
  const [token, setToken] = useState('');

  useEffect(() => {
    fetch('http://localhost:3001/token')
      .then(res => res.json())
      .then(data => setToken(data.token));
  }, []);

  if (!token) return <div>Loading...</div>;

  return (
    <MagicBellProvider token={token}>
      <FloatingInbox
        InboxComponent={() => <Inbox ItemComponent={CustomNotificationItem} />}
      />
    </MagicBellProvider>
  );
}

