          data: event.data,
          error: e
        });
      }
    });
    this.#socket.addEventListener("open", () => {
      log.info("socket: open");
    });
    this.#socket.addEventListener("close", () => {
      log.info("socket: close");
    });
    this.#socket.addEventListener("error", err => {
      log.error("socket: error", err);
    });
  }
  async #getUrl() {
    const jwtToken = this.#client.config.token;
    ensure(jwtToken, "MagicBell JWT token missing from client config");
    const apiKey = getApiKeyFromToken(jwtToken);
    ensure(apiKey, "Failed to extract API key from JWT token");
    const token = await this.#getToken();
    const url = new URL(this.#socketUrl);
    url.searchParams.set("api_key", apiKey);
    url.searchParams.set("token", token);
    this.#origin = url.origin;
    return url.toString();
  }
  async #getToken() {
    if (this.#token) return this.#token;
    const {
      data,
      metadata: res
    } = await this.#client.channels.saveInboxToken({
      token: getSessionId()
    });
    ensure(isOK(res), `Failed to save Inbox token: ${res.status} ${res.statusText}`);
    ensure(data?.token, "Unexpected server response, missing token");
    this.#token = data.token;
    return this.#token;
  }
  listen(filter: Parameters<Collection<Event>["find"]>[0], cb: (event: Event) => void) {
    this.find(filter).observe(change => {
      if (change.type !== "added") return;
      cb(change.doc);
    });
  }
}

